package com.maum.backend.calling.repository

import com.maum.backend.calling.domain.CallSession
import com.maum.backend.calling.domain.CallSessionStatus

interface CallSessionRepository {
    fun save(session: CallSession): CallSession
    fun findById(sessionId: String): CallSession?
    fun findByUserId(userId: String): CallSession?
    fun findFirstWaitingExcluding(excludeUserId: String): CallSession?
    fun findActiveByUserId(userId: String): CallSession?
    fun deleteById(sessionId: String)
    fun updateStatus(sessionId: String, status: CallSessionStatus): CallSession
}
```

**`calling-service/src/main/kotlin/com/maum/backend/calling/service/CallMatchingService.kt`**

```kotlin
package com.maum.backend.calling.service

import com.maum.backend.calling.domain.CallSession
import com.maum.backend.calling.domain.CallSessionStatus

interface CallMatchingService {
    // 매칭 대기열 등록 및 매칭 시도
    fun requestMatching(userId: String): CallSession

    // 매칭 수락 (양측 모두 수락 시 IN_CALL로 전환)
    fun acceptMatch(sessionId: String, userId: String): CallSession

    // 매칭 또는 통화 취소
    fun cancelSession(sessionId: String, userId: String)

    // 연결 끊김 처리
    fun handleDisconnection(sessionId: String, userId: String): CallSession

    // 현재 세션 상태 조회
    fun getSession(sessionId: String): CallSession
}
```

