**`calling-service/src/test/kotlin/com/maum/backend/calling/service/CallMatchingServiceTest.kt`** (Red 단계 테스트)

```kotlin
package com.maum.backend.calling.service

import com.maum.backend.calling.domain.CallSession
import com.maum.backend.calling.domain.CallSessionStatus
import com.maum.backend.calling.exception.*
import com.maum.backend.calling.repository.CallSessionRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.*
import org.mockito.junit.jupiter.MockitoExtension
import java.time.Instant
import java.util.UUID

@ExtendWith(MockitoExtension::class)
class CallMatchingServiceTest {

    @Mock
    private lateinit var callSessionRepository: CallSessionRepository

    @InjectMocks
    private lateinit var callMatchingService: CallMatchingServiceImpl

    private lateinit var userAId: String
    private lateinit var userBId: String

    @BeforeEach
    fun setUp() {
        userAId = "user-a-${UUID.randomUUID()}"
        userBId = "user-b-${UUID.randomUUID()}"
    }

    // ────────────────────────────────────────────
    // 정상 케이스
    // ────────────────────────────────────────────

    @Test
    fun `should create waiting session when no matching candidate exists`() {
        // given: 대기 중인 다른 사용자가 없고, userA에게 기존 활성 세션도 없음
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(null)
        val savedSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.save(any())).thenReturn(savedSession)

        // when
        val result = callMatchingService.requestMatching(userAId)

        // then
        assertThat(result.status).isEqualTo(CallSessionStatus.WAITING)
        assertThat(result.userId).isEqualTo(userAId)
        assertThat(result.matchedUserId).isNull()
        verify(callSessionRepository).save(any())
    }

    @Test
    fun `should return matched session when waiting candidate exists`() {
        // given: userB가 이미 대기 중
        val waitingSession = CallSession(
            sessionId = "session-b",
            userId = userBId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(waitingSession)

        val matchedSessionA = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.MATCHED,
            matchedUserId = userBId,
            matchedSessionId = "session-b"
        )
        val matchedSessionB = waitingSession.copy(
            status = CallSessionStatus.MATCHED,
            matchedUserId = userAId,
            matchedSessionId = "session-a"
        )
        `when`(callSessionRepository.save(any())).thenReturn(matchedSessionA)
        `when`(callSessionRepository.updateStatus(eq("session-b"), eq(CallSessionStatus.MATCHED)))
            .thenReturn(matchedSessionB)

        // when
        val result = callMatchingService.requestMatching(userAId)

        // then
        assertThat(result.status).isEqualTo(CallSessionStatus.MATCHED)
        assertThat(result.matchedUserId).isEqualTo(userBId)
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 1: 이미 매칭된(활성) 사용자
    // ────────────────────────────────────────────

    @Test
    fun `should throw AlreadyMatchedException when user already has active session`() {
        // given: userA가 이미 MATCHED 상태
        val existingSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.MATCHED,
            matchedUserId = userBId
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(existingSession)

        // when & then
        assertThrows<AlreadyMatchedException> {
            callMatchingService.requestMatching(userAId)
        }
        verify(callSessionRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyMatchedException when user is already in call`() {
        // given: userA가 IN_CALL 상태
        val inCallSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.IN_CALL,
            matchedUserId = userBId
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(inCallSession)

        // when & then
        assertThrows<AlreadyMatchedException> {
            callMatchingService.requestMatching(userAId)
        }
    }

    @Test
    fun `should throw AlreadyMatchedException when user is waiting in queue`() {
        // given: userA가 이미 WAITING 상태 (중복 요청)
        val waitingSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(waitingSession)

        // when & then
        assertThrows<AlreadyMatchedException> {
            callMatchingService.requestMatching(userAId)
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 2: 자기 자신과 매칭 방지
    // ────────────────────────────────────────────

    @Test
    fun `should throw SelfMatchingException when only candidate is same user`() {
        // given: 대기열에 자기 자신의 세션만 존재하는 비정상 상황
        val selfSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        // findFirstWaitingExcluding 는 excludeUserId를 제외하므로 null 반환이 정상이지만
        // 구현 버그로 자신의 세션이 반환될 때를 방어
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(selfSession)

        // when & then
        assertThrows<SelfMatchingException> {
            callMatchingService.requestMatching(userAId)
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 3: 취소된/종료된 세션에 매칭 시도
    // ────────────────────────────────────────────

    @Test
    fun `should throw InvalidSessionException when accepting cancelled session`() {
        // given: CANCELLED 상태의 세션
        val cancelledSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.CANCELLED
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(cancelledSession)

        // when & then
        assertThrows<InvalidSessionException> {
            callMatchingService.acceptMatch("session-a", userAId)
        }
    }

    @Test
    fun `should throw InvalidSessionException when accepting ended session`() {
        // given: ENDED 상태의 세션
        val endedSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.ENDED
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(endedSession)

        // when & then
        assertThrows<InvalidSessionException> {
            callMatchingService.acceptMatch("session-a", userAId)
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 4: 연결 끊김 후 상태 전이
    // ────────────────────────────────────────────

    @Test
    fun `should transition to DISCONNECTED and allow re-matching after disconnection`() {
        // given: IN_CALL 중 연결 끊김
        val inCallSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.IN_CALL,
            matchedUserId = userBId,
            matchedSessionId = "session-b"
        )
        val disconnectedSession = inCallSession.copy(status = CallSessionStatus.DISCONNECTED)
        `when`(callSessionRepository.findById("session-a")).thenReturn(inCallSession)
        `when`(callSessionRepository.updateStatus("session-a", CallSessionStatus.DISCONNECTED))
            .thenReturn(disconnectedSession)

        // when
        val result = callMatchingService.handleDisconnection("session-a", userAId)

        // then
        assertThat(result.status).isEqualTo(CallSessionStatus.DISCONNECTED)
        verify(callSessionRepository).updateStatus("session-a", CallSessionStatus.DISCONNECTED)
    }

    @Test
    fun `should allow new matching request after previous session was disconnected`() {
        // given: 이전 세션이 DISCONNECTED 상태 (활성 세션 없음)
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(null)
        val newWaitingSession = CallSession(
            sessionId = "session-new",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.save(any())).thenReturn(newWaitingSession)

        // when
        val result = callMatchingService.requestMatching(userAId)

        // then: 재매칭 허용
        assertThat(result.status).isEqualTo(CallSessionStatus.WAITING)
        assertThat(result.userId).isEqualTo(userAId)
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 5: 매칭 후 상대방이 취소 (경쟁 조건)
    // ────────────────────────────────────────────

    @Test
    fun `should throw InvalidSessionException when matched partner session is already cancelled`() {
        // given: userA 매칭 완료, 그러나 상대 세션(userB)이 이미 CANCELLED
        val matchedSessionA = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.MATCHED,
            matchedUserId = userBId,
            matchedSessionId = "session-b"
        )
        val cancelledSessionB = CallSession(
            sessionId = "session-b",
            userId = userBId,
            status = CallSessionStatus.CANCELLED
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(matchedSessionA)
        `when`(callSessionRepository.findById("session-b")).thenReturn(cancelledSessionB)

        // when & then: acceptMatch 시 상대 세션 유효성 검증 실패
        assertThrows<InvalidSessionException> {
            callMatchingService.acceptMatch("session-a", userAId)
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 6: 대기 세션 TTL 만료
    // ────────────────────────────────────────────

    @Test
    fun `should throw SessionExpiredException when waiting session is expired`() {
        // given: 5분 이상 지난 WAITING 세션 (만료)
        val expiredSession = CallSession(
            sessionId = "session-old",
            userId = userBId,
            status = CallSessionStatus.WAITING,
            createdAt = Instant.now().minusSeconds(360) // 6분 경과
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(expiredSession)

        // when & then: 만료 세션과의 매칭 방지
        assertThrows<SessionExpiredException> {
            callMatchingService.requestMatching(userAId)
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 7: 입력값 검증 (null/빈 userId)
    // ────────────────────────────────────────────

    @Test
    fun `should throw IllegalArgumentException when userId is blank`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            callMatchingService.requestMatching("")
        }
        verify(callSessionRepository, never()).findActiveByUserId(any())
    }

    @Test
    fun `should throw IllegalArgumentException when userId is blank with whitespace`() {
        // when & then
        assertThrows<IllegalArgumentException> {
            callMatchingService.requestMatching("   ")
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 8: 세션 조회 실패
    // ────────────────────────────────────────────

    @Test
    fun `should throw InvalidSessionException when session not found`() {
        // given: 존재하지 않는 sessionId
        `when`(callSessionRepository.findById("non-existent")).thenReturn(null)

        // when & then
        assertThrows<InvalidSessionException> {
            callMatchingService.getSession("non-existent")
        }
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 9: 취소 시 권한 검증
    // ────────────────────────────────────────────

    @Test
    fun `should throw SecurityException when different user tries to cancel session`() {
        // given: session-a는 userA 소유이지만 userB가 취소 시도
        val sessionA = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(sessionA)

        // when & then
        assertThrows<SecurityException> {
            callMatchingService.cancelSession("session-a", userBId)
        }
        verify(callSessionRepository, never()).updateStatus(any(), any())
    }

    // ────────────────────────────────────────────
    // 엣지 케이스 10: WAITING 상태가 아닌 세션 취소
    // ────────────────────────────────────────────

    @Test
    fun `should cancel waiting session successfully`() {
        // given
        val waitingSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(waitingSession)
        `when`(callSessionRepository.updateStatus("session-a", CallSessionStatus.CANCELLED))
            .thenReturn(waitingSession.copy(status = CallSessionStatus.CANCELLED))

        // when: 취소는 예외 없이 완료
        callMatchingService.cancelSession("session-a", userAId)

        // then
        verify(callSessionRepository).updateStatus("session-a", CallSessionStatus.CANCELLED)
    }

    @Test
    fun `should throw InvalidSessionException when cancelling already ended session`() {
        // given: ENDED 세션 취소 시도
        val endedSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.ENDED
        )
        `when`(callSessionRepository.findById("session-a")).thenReturn(endedSession)

        // when & then
        assertThrows<InvalidSessionException> {
            callMatchingService.cancelSession("session-a", userAId)
        }
    }

    // ────────────────────────────────────────────
    // 동시성 시나리오 (낙관적 락 검증)
    // ────────────────────────────────────────────

    @Test
    fun `should throw NoMatchingCandidateException when concurrent match steals candidate`() {
        // given: 대기 후보가 조회 시점에는 있었으나 저장 직전 다른 요청이 선점
        val candidateSession = CallSession(
            sessionId = "session-b",
            userId = userBId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(candidateSession)
        // 실제 updateStatus 호출 시 ConcurrentModificationException 시뮬레이션
        `when`(callSessionRepository.updateStatus(eq("session-b"), eq(CallSessionStatus.MATCHED)))
            .thenThrow(ConcurrentModificationException("이미 다른 요청이 이 세션을 선점했습니다."))

        // when & then: 서비스는 ConcurrentModificationException을 NoMatchingCandidateException으로 변환
        assertThrows<NoMatchingCandidateException> {
            callMatchingService.requestMatching(userAId)
        }
    }
}
