**`calling-service/src/main/kotlin/com/maum/backend/calling/domain/CallSession.kt`**

```kotlin
package com.maum.backend.calling.domain

import java.time.Instant

enum class CallSessionStatus {
    WAITING,
    MATCHED,
    IN_CALL,
    ENDED,
    CANCELLED,
    DISCONNECTED
}

data class CallSession(
    val sessionId: String,
    val userId: String,
    var status: CallSessionStatus = CallSessionStatus.WAITING,
    var matchedUserId: String? = null,
    var matchedSessionId: String? = null,
    val createdAt: Instant = Instant.now(),
    var updatedAt: Instant = Instant.now()
) {
    fun isWaiting(): Boolean = status == CallSessionStatus.WAITING

    fun isMatched(): Boolean =
        status == CallSessionStatus.MATCHED || status == CallSessionStatus.IN_CALL

    fun isActive(): Boolean = status in listOf(
        CallSessionStatus.WAITING,
        CallSessionStatus.MATCHED,
        CallSessionStatus.IN_CALL
    )
}
```

