package com.maum.backend.calling.exception

class AlreadyMatchedException(userId: String) :
    RuntimeException("사용자 $userId 는 이미 매칭 중입니다.")

class NoMatchingCandidateException(userId: String) :
    RuntimeException("사용자 $userId 의 매칭 상대를 찾을 수 없습니다.")

class SelfMatchingException(userId: String) :
    RuntimeException("사용자 $userId 는 자기 자신과 매칭될 수 없습니다.")

class InvalidSessionException(sessionId: String) :
    RuntimeException("세션 $sessionId 은 유효하지 않은 상태입니다.")

class SessionExpiredException(sessionId: String) :
    RuntimeException("세션 $sessionId 은 만료되었습니다.")

class MatchingRateLimitExceededException(userId: String) :
    RuntimeException("사용자 $userId 의 매칭 요청이 너무 빈번합니다.")
