    private lateinit var userBId: String

    @BeforeEach
    fun setUp() {
        userAId = "user-a-${UUID.randomUUID()}"
        userBId = "user-b-${UUID.randomUUID()}"
    }

    // ────────────────────────────────────────────
    // 정상 케이스
    // ────────────────────────────────────────────

    @Test
    fun `should create waiting session when no matching candidate exists`() {
        // given: 대기 중인 다른 사용자가 없고, userA에게 기존 활성 세션도 없음
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(null)
        val savedSession = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.save(any())).thenReturn(savedSession)

        // when
        val result = callMatchingService.requestMatching(userAId)

        // then
        assertThat(result.status).isEqualTo(CallSessionStatus.WAITING)
        assertThat(result.userId).isEqualTo(userAId)
        assertThat(result.matchedUserId).isNull()
        verify(callSessionRepository).save(any())
    }

    @Test
    fun `should return matched session when waiting candidate exists`() {
        // given: userB가 이미 대기 중
        val waitingSession = CallSession(
            sessionId = "session-b",
            userId = userBId,
            status = CallSessionStatus.WAITING
        )
        `when`(callSessionRepository.findActiveByUserId(userAId)).thenReturn(null)
        `when`(callSessionRepository.findFirstWaitingExcluding(userAId)).thenReturn(waitingSession)

        val matchedSessionA = CallSession(
            sessionId = "session-a",
            userId = userAId,
            status = CallSessionStatus.MATCHED,
            matchedUserId = userBId,
            matchedSessionId = "session-b"
        )
        val matchedSessionB = waitingSession.copy(
            status = CallSessionStatus.MATCHED,
            matchedUserId = userAId,
            matchedSessionId = "session-a"
