```kotlin
package com.maum.backend.calling.service

import com.maum.backend.calling.domain.CallSession
import com.maum.backend.calling.domain.CallSessionStatus
import com.maum.backend.calling.exception.*
import com.maum.backend.calling.repository.CallSessionRepository
import org.springframework.stereotype.Service
import java.time.Instant
import java.time.temporal.ChronoUnit
import java.util.UUID

@Service
class CallMatchingServiceImpl(
    private val callSessionRepository: CallSessionRepository
) : CallMatchingService {

    companion object {
        private const val SESSION_TTL_MINUTES = 5L
    }

    override fun requestMatching(userId: String): CallSession {
        require(userId.isNotBlank()) { "userId는 비어있을 수 없습니다." }

        // 이미 활성 세션이 있으면 재요청 불가
        callSessionRepository.findActiveByUserId(userId)?.let {
            throw AlreadyMatchedException(userId)
        }

        // 대기 중인 상대 탐색
        val candidate = callSessionRepository.findFirstWaitingExcluding(userId)

        return if (candidate == null) {
            // 대기 상태로 등록
            val newSession = CallSession(
                sessionId = UUID.randomUUID().toString(),
                userId = userId,
                status = CallSessionStatus.WAITING
            )
            callSessionRepository.save(newSession)
        } else {
            // 자기 자신과 매칭 방어
            if (candidate.userId == userId) {
                throw SelfMatchingException(userId)
            }

            // TTL 만료 검증
            val expiredAt = candidate.createdAt.plus(SESSION_TTL_MINUTES, ChronoUnit.MINUTES)
            if (Instant.now().isAfter(expiredAt)) {
                throw SessionExpiredException(candidate.sessionId)
            }

            // 매칭 처리
            val newSessionId = UUID.randomUUID().toString()
            val newSession = CallSession(
                sessionId = newSessionId,
                userId = userId,
                status = CallSessionStatus.MATCHED,
                matchedUserId = candidate.userId,
                matchedSessionId = candidate.sessionId
            )

            try {
                callSessionRepository.updateStatus(candidate.sessionId, CallSessionStatus.MATCHED)
            } catch (e: ConcurrentModificationException) {
                throw NoMatchingCandidateException(userId)
            }

            callSessionRepository.save(newSession)
        }
    }

    override fun acceptMatch(sessionId: String, userId: String): CallSession {
        val session = callSessionRepository.findById(sessionId)
            ?: throw InvalidSessionException(sessionId)

        if (!session.isMatched()) {
            throw InvalidSessionException(sessionId)
        }

        // 상대방 세션 유효성 검증
        session.matchedSessionId?.let { partnerSessionId ->
            val partnerSession = callSessionRepository.findById(partnerSessionId)
            if (partnerSession == null || !partnerSession.isActive()) {
                throw InvalidSessionException(partnerSessionId)
            }
        }

        return callSessionRepository.updateStatus(sessionId, CallSessionStatus.IN_CALL)
    }

    override fun cancelSession(sessionId: String, userId: String) {
        val session = callSessionRepository.findById(sessionId)
            ?: throw InvalidSessionException(sessionId)

        if (session.userId != userId) {
            throw SecurityException("세션 $sessionId 에 대한 취소 권한이 없습니다.")
        }

        if (session.status == CallSessionStatus.ENDED ||
            session.status == CallSessionStatus.CANCELLED
        ) {
            throw InvalidSessionException(sessionId)
        }

        callSessionRepository.updateStatus(sessionId, CallSessionStatus.CANCELLED)
    }

    override fun handleDisconnection(sessionId: String, userId: String): CallSession {
        val session = callSessionRepository.findById(sessionId)
            ?: throw InvalidSessionException(sessionId)

        return callSessionRepository.updateStatus(sessionId, CallSessionStatus.DISCONNECTED)
    }

    override fun getSession(sessionId: String): CallSession {
        return callSessionRepository.findById(sessionId)
            ?: throw InvalidSessionException(sessionId)
    }
}
